TUSDATA.cities=[
{id:"boston",name:"Boston",lon:-71.06,lat:42.36,founded:1630,appears:1750,joins:1776,tier:1,
 facts:[["Founded","1630, Massachusetts Bay Colony"],["Role","Colonial port; cradle of the Revolution"],["First","America's first subway opened here, 1897"]],
 pop:[[1750,15000],[1800,24937],[1850,136881],[1900,560892],[1950,801444],[2020,675647]],
 eras:[
  {from:1750,to:1775,text:"A British colonial seaport of about 15,000, living on shipbuilding, cod, rum, and Atlantic trade. Resistance to imperial taxation centered here: Stamp Act riots in 1765, the Boston Massacre in 1770, the Tea Party in 1773, and the punitive closure of the port in 1774."},
  {from:1775,to:1830,text:"The Revolution opened here: Lexington and Concord, Bunker Hill, then an eleven-month siege until the British evacuated in March 1776. Afterward Boston rebuilt on maritime commerce and the China trade, added Bulfinch's State House in 1798, and incorporated as a city in 1822."},
  {from:1830,to:1900,text:"Irish famine immigration after 1845 remade the population; the city was also a center of abolitionism and publishing. Land-making filled the Back Bay, textile fortunes funded banks and colleges, the Great Fire of 1872 leveled downtown blocks, and America's first subway opened in 1897."},
  {from:1900,to:1980,text:"An ethnic, ward-politics city of dockworkers and mill money whose port and industries slowly declined. The 1919 molasses flood killed 21 in the North End. Postwar urban renewal demolished the West End, and court-ordered school busing in 1974-76 set off violent resistance."},
  {from:1980,to:2026,text:"Universities, hospitals, finance, and biotechnology rebuilt the economy; Kendall Square across the river became a global life-sciences hub. The Big Dig (1991-2007) buried the Central Artery. Population recovered past 675,000 by 2020, with high housing costs the defining civic strain."}
 ],
 sources:["U.S. Census Bureau, decennial census","National Park Service — Boston National Historical Park","Massachusetts Historical Society"]},
{id:"newyork",name:"New York",lon:-74.01,lat:40.71,founded:1624,appears:1750,joins:1776,tier:1,
 facts:[["Founded","1624, as Dutch New Amsterdam"],["Role","Premier US port, financial and immigration gateway"],["Note","US capital 1785-1790; Washington inaugurated here 1789"]],
 pop:[[1800,60515],[1850,515547],[1900,3437202],[1950,7891957],[2020,8804190]],
 eras:[
  {from:1750,to:1783,text:"A leading British colonial port on Manhattan's tip, trading grain, sugar, and enslaved people; about one in five residents was enslaved. British forces seized the city in September 1776 and held it as their North American headquarters until Evacuation Day, November 1783; great fires burned swaths of it in 1776 and 1778."},
  {from:1783,to:1825,text:"National capital 1785-1790, where Washington took the first presidential oath in 1789. Merchants founded what became the Stock Exchange under a Wall Street buttonwood in 1792, the 1811 plan gridded Manhattan, and the Erie Canal's completion in 1825 locked in commercial supremacy over rival ports."},
  {from:1825,to:1898,text:"The nation's immigration gateway — Castle Garden, then Ellis Island from 1892 — and its financial center. Croton water arrived in 1842, Central Park opened from 1858, Draft Riots killed over a hundred in 1863, and the Brooklyn Bridge rose in 1883. Consolidation in 1898 joined five boroughs, 3.4 million people."},
  {from:1898,to:1945,text:"The subway opened in 1904 and the skyline went vertical, capped by the Empire State Building in 1931. The 1911 Triangle fire killed 146 garment workers and drove labor reform. Harlem became the capital of Black America; by the 1920s this was the largest city on earth."},
  {from:1945,to:2026,text:"Postwar capital of finance, media, and the United Nations (headquartered here from 1952). Near-bankruptcy in 1975, high crime, then steep 1990s decline in violence. The September 11, 2001 attacks destroyed the World Trade Center and killed about 2,750 here. Population reached a record 8.8 million in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Library of Congress","New-York Historical Society"]},
{id:"philadelphia",name:"Philadelphia",lon:-75.16,lat:39.95,founded:1682,appears:1750,joins:1776,tier:1,
 facts:[["Founded","1682, by William Penn"],["Role","Revolutionary capital; Declaration and Constitution signed here"],["Nickname","The Workshop of the World"]],
 pop:[[1800,41220],[1850,121376],[1900,1293697],[1950,2071605],[2020,1603797]],
 eras:[
  {from:1750,to:1776,text:"Penn's Quaker port grew into one of the largest cities in British America, a grain-export hub with Franklin's civic inventions — the Library Company, the American Philosophical Society, Pennsylvania Hospital (1751). The First and Second Continental Congresses met here as the imperial crisis deepened."},
  {from:1776,to:1800,text:"Independence was declared at the State House in July 1776; the British occupied the city in 1777-78. The Constitutional Convention met here in 1787, and Philadelphia served as the national capital 1790-1800. The 1793 yellow fever epidemic killed roughly 5,000, a tenth of the population."},
  {from:1800,to:1854,text:"An early industrial center of textiles, machine shops, and the Fairmount Water Works (1815), losing commercial primacy to New York. Nativist anti-Catholic riots burned churches in 1844. The 1854 Consolidation Act merged the city with Philadelphia County, multiplying its territory and population."},
  {from:1854,to:1950,text:"The Workshop of the World: Baldwin locomotives, Cramp shipyards, Stetson hats, and vast textile mills, worked by European immigrants and, after 1916, Great Migration arrivals. The 1876 Centennial Exhibition drew ten million visitors. Population peaked near 2.1 million around 1950."},
  {from:1950,to:2026,text:"Deindustrialization cut manufacturing jobs and a quarter of the population by 2000. The 1985 MOVE bombing by city police killed eleven and burned a Black neighborhood block. Universities, medicine, and a growing downtown drove recovery; population turned upward after 2010 to 1.6 million."}
 ],
 sources:["U.S. Census Bureau, decennial census","National Park Service — Independence National Historical Park","Historical Society of Pennsylvania"]},
{id:"baltimore",name:"Baltimore",lon:-76.61,lat:39.29,founded:1729,appears:1750,joins:1776,tier:2,
 facts:[["Founded","1729, on the Patapsco River"],["Role","Flour and clipper port; B&O Railroad birthplace"],["Anthem","Fort McHenry's 1814 defense inspired The Star-Spangled Banner"]],
 pop:[[1800,26514],[1850,169054],[1900,508957],[1950,949708],[2020,585708]],
 eras:[
  {from:1750,to:1776,text:"A young tobacco-inspection town on the Patapsco that found its business milling and shipping wheat from the Pennsylvania and Maryland backcountry. Flour exports to the Caribbean and southern Europe made it the fastest-growing port in the colonies on the eve of the Revolution."},
  {from:1776,to:1830,text:"Privateers in swift Baltimore clippers preyed on British shipping in the Revolution and the War of 1812. In September 1814 the city repulsed a British assault; the bombardment of Fort McHenry inspired Francis Scott Key's anthem. The Baltimore & Ohio Railroad, chartered 1827, was America's first common-carrier line; by 1830 this was the nation's second-largest city."},
  {from:1830,to:1904,text:"A rail and immigration port with the largest free Black community in the antebellum United States alongside continued slavery. The Pratt Street Riot of April 1861 drew the Civil War's first bloodshed. Canning, garment work, and steel followed; the Great Fire of February 1904 destroyed over 1,500 downtown buildings."},
  {from:1904,to:1980,text:"Rebuilt quickly, then boomed on heavy industry: Sparrows Point steel, shipyards that launched Liberty ships, and Glenn L. Martin aircraft in the World Wars. Segregation was codified early (a 1910 residential ordinance) and contested long; riots followed King's assassination in 1968 as industry began leaving."},
  {from:1980,to:2026,text:"Harborplace (1980) and Camden Yards (1992) anchored waterfront renewal while steel and port jobs shrank and population fell from its 950,000 peak toward 585,000. Johns Hopkins institutions became the largest employer. In 2024 the Francis Scott Key Bridge collapsed after a container-ship strike, killing six."}
 ],
 sources:["U.S. Census Bureau, decennial census","National Park Service — Fort McHenry National Monument","Maryland Center for History and Culture"]},
{id:"charleston",name:"Charleston",lon:-79.93,lat:32.78,founded:1670,appears:1750,joins:1776,tier:1,
 facts:[["Founded","1670, as Charles Town"],["Role","Rice-wealth capital and principal port of the North American slave trade"],["First","First shots of the Civil War, Fort Sumter, 1861"]],
 pop:[[1790,16359],[1850,42985],[1900,55807],[1950,70174],[2020,150227]],
 eras:[
  {from:1750,to:1776,text:"The wealthiest city in British North America per capita, built on rice and indigo grown by enslaved Africans. It was the mainland's principal slave port: roughly 40 percent of captive Africans brought to the colonies landed here, quarantined at Sullivan's Island. Enslaved people were the majority of the lowcountry population."},
  {from:1776,to:1861,text:"The city repelled a British fleet in 1776 but fell to siege in 1780. Cotton and rice wealth rebuilt it; Denmark Vesey's planned 1822 uprising brought savage reprisals. Charleston led the 1832-33 nullification fight, and South Carolina's secession convention voted the Union apart here in December 1860."},
  {from:1861,to:1900,text:"The Civil War began in its harbor with the bombardment of Fort Sumter, April 12, 1861; Union siege guns shelled the city for nearly two years. Emancipation upended the lowcountry economy. The 1886 earthquake, among the strongest ever recorded on the East Coast, killed dozens and cracked thousands of buildings."},
  {from:1900,to:1975,text:"The Navy Yard, opened 1901 on the Cooper River, became the economic mainstay through two World Wars and the Cold War. Jim Crow ruled civic life. In 1931 Charleston enacted the nation's first historic-district zoning ordinance, turning preservation of its colonial fabric into policy."},
  {from:1975,to:2026,text:"Tourism and the port drove a long boom under Mayor Joseph Riley (1975-2016). Hurricane Hugo struck directly in 1989; the Navy base closed in 1996. In 2015 a white supremacist murdered nine Black worshippers at Emanuel AME Church. The 2018 International African American Museum project opened at Gadsden's Wharf in 2023."}
 ],
 sources:["U.S. Census Bureau, decennial census","National Park Service — Fort Sumter and Fort Moultrie","South Carolina Historical Society"]},
{id:"savannah",name:"Savannah",lon:-81.09,lat:32.08,founded:1733,appears:1750,joins:1776,tier:2,
 facts:[["Founded","1733, by James Oglethorpe"],["Role","Rice and cotton port on Oglethorpe's ward-and-square plan"],["Note","Sherman's March to the Sea ended here, December 1864"]],
 pop:[[1800,5146],[1850,15312],[1900,54244],[1950,119638],[2020,147780]],
 eras:[
  {from:1750,to:1776,text:"Oglethorpe's planned town of wards and squares, laid out in 1733 beside Tomochichi's Yamacraw village. The trustees' ban on slavery was lifted in 1751, and Savannah became a royal-colony port whose rice economy ran on enslaved African labor and lowcountry plantation expansion."},
  {from:1776,to:1865,text:"The British took the city in 1778; a Franco-American assault to retake it in 1779 failed with heavy losses, including Casimir Pulaski. Eli Whitney's gin, invented at nearby Mulberry Grove in 1793, made Savannah a great cotton port. Fire and yellow fever both ravaged it in 1820. Sherman's March ended here in December 1864; the city surrendered intact."},
  {from:1865,to:1955,text:"Cotton factorage revived on Factors Walk, and the Cotton Exchange (1876) priced much of the world's upland crop until the boll weevil collapse of the 1920s. Naval stores, then pulp and paper mills in the 1930s, sustained the port economy through depression and war."},
  {from:1955,to:2026,text:"The Historic Savannah Foundation, formed 1955, saved the largest intact colonial-era plan in the country from demolition. The Savannah College of Art and Design (1978) filled old buildings with students. Tourism boomed, and the Garden City terminal grew into one of the busiest US container ports."}
 ],
 sources:["U.S. Census Bureau, decennial census","Georgia Historical Society","National Park Service"]},
{id:"richmond",name:"Richmond",lon:-77.44,lat:37.54,founded:1737,appears:1750,joins:1776,tier:2,
 facts:[["Founded","1737, at the falls of the James"],["Role","Virginia's capital from 1780; Confederate capital 1861-65"],["First","First successful electric streetcar system in the US, 1888"]],
 pop:[[1800,5737],[1850,27570],[1900,85050],[1950,230310],[2020,226610]],
 eras:[
  {from:1750,to:1780,text:"A small tobacco-inspection town laid out in 1737 by William Byrd II at the falls of the James, where hogsheads from upcountry plantations were warehoused and traded. Patrick Henry delivered his 'liberty or death' speech at St. John's Church in 1775 as revolution approached."},
  {from:1780,to:1861,text:"Virginia's capital from 1780; Benedict Arnold's British raiders burned it in 1781. Gabriel's planned slave rebellion was betrayed and crushed in 1800. Flour mills and the Tredegar Iron Works (1837) industrialized the falls, and Shockoe Bottom became one of the largest slave-trading markets in the United States, second only to New Orleans."},
  {from:1861,to:1900,text:"Capital of the Confederacy from May 1861, ringed by four years of campaigns; the retreating government's evacuation fire gutted the business district in April 1865. Rebuilding brought tobacco factories, ironworks, and in 1888 the nation's first successful electric streetcar system. Jackson Ward rose as a center of Black enterprise."},
  {from:1900,to:1970,text:"Maggie L. Walker chartered a bank in Jackson Ward in 1903, the first American woman to do so. Tobacco, banking, and state government sustained the city while Jim Crow hardened; Monument Avenue filled with Confederate statuary, and mid-century highway construction razed much of Jackson Ward."},
  {from:1970,to:2026,text:"A disputed 1970 annexation diluted Black voting power until courts intervened; a Black-majority council took office in 1977, and Virginia elected Richmond's L. Douglas Wilder the nation's first elected Black governor in 1989. In 2020, after mass protests, the city removed its Confederate monuments. Universities and state government anchor the economy."}
 ],
 sources:["U.S. Census Bureau, decennial census","Library of Virginia","National Park Service — Richmond National Battlefield Park"]},
{id:"williamsburg",name:"Williamsburg",lon:-76.71,lat:37.27,founded:1632,appears:1750,joins:1776,tier:3,
 facts:[["Founded","1632 as Middle Plantation; renamed 1699"],["Role","Capital of colonial Virginia, 1699-1780"],["Note","College of William & Mary chartered 1693, America's second-oldest college"]],
 eras:[
  {from:1750,to:1780,text:"Capital of Britain's largest mainland colony: Governor's Palace, Capitol, and the College of William & Mary (1693) along Duke of Gloucester Street. Patrick Henry's Stamp Act resolves passed in the House of Burgesses in 1765, and the 1775 gunpowder incident pushed Virginia toward revolt. Roughly half the town's people were enslaved."},
  {from:1780,to:1926,text:"The capital moved to Richmond in 1780 and Williamsburg became a quiet courthouse and college town. The Battle of Williamsburg was fought on its outskirts in May 1862. The Public Hospital of 1773, the first public institution in British America devoted to mental illness, remained a fixture."},
  {from:1926,to:2026,text:"From 1926 Rector W.A.R. Goodwin persuaded John D. Rockefeller Jr. to fund restoration of the colonial capital; hundreds of later buildings were removed and the eighteenth-century town rebuilt as Colonial Williamsburg, the country's largest living-history museum. Tourism and the college now define the economy."}
 ],
 sources:["Colonial Williamsburg Foundation","Encyclopaedia Britannica","Library of Congress"]},
{id:"neworleans",name:"New Orleans",lon:-90.07,lat:29.95,founded:1718,appears:1750,joins:1803,tier:1,
 facts:[["Founded","1718, by Bienville for France"],["Role","Mississippi gateway port; birthplace of jazz"],["Note","Largest slave market in the antebellum United States"]],
 pop:[[1810,17242],[1850,116375],[1900,287104],[1950,570445],[2020,383997]],
 eras:[
  {from:1750,to:1803,text:"French colonial capital of Louisiana, founded 1718 on a Mississippi crescent long used by the Chitimacha and neighbors, then ceded to Spain in 1762. Fires in 1788 and 1794 destroyed the old town; the Spanish rebuilt the French Quarter in brick. A large community of free people of color and a sugar boom marked the 1790s; France briefly retook the colony before selling it in 1803."},
  {from:1803,to:1862,text:"Transferred to the United States in December 1803 with the Louisiana Purchase. Jackson's polyglot force repelled the British at Chalmette in January 1815. Steamboats made it the great cotton-and-sugar entrepot — by 1840 among the nation's largest and richest cities — and the largest slave market in the country. Farragut's fleet captured it in April 1862."},
  {from:1862,to:1927,text:"Union occupation, then violent Reconstruction: the 1866 Mechanics' Institute massacre and the 1874 Battle of Liberty Place. Around 1900, Black musicians in its dance halls and parades forged jazz — Bolden, then Armstrong. The 1927 flood spared the city only after engineers dynamited the levee downstream at Caernarvon, flooding poorer parishes."},
  {from:1927,to:2005,text:"A port, oil, and shipbuilding economy: Higgins boats for World War II, later NASA's Michoud rocket plant. Population peaked at 627,525 in 1960 before suburban flight. Hurricane Betsy flooded the Lower Ninth Ward in 1965. Tourism, Mardi Gras, and the French Quarter became economic mainstays."},
  {from:2005,to:2026,text:"Hurricane Katrina's levee failures on August 29, 2005 flooded about 80 percent of the city; more than 1,300 Louisianians died and hundreds of thousands were displaced. Population fell by over half, recovering to 383,997 by 2020. Rebuilt levees, tourism, the port, and persistent inequality define the post-Katrina city."}
 ],
 sources:["U.S. Census Bureau, decennial census","The Historic New Orleans Collection","National Park Service — New Orleans Jazz National Historical Park"]},
{id:"stlouis",name:"St. Louis",lon:-90.20,lat:38.63,founded:1764,appears:1764,joins:1803,tier:1,
 facts:[["Founded","1764, by Laclède and Chouteau for France"],["Role","Fur-trade capital and Gateway to the West"],["Note","Lewis and Clark's expedition departed and returned here, 1804-1806"]],
 pop:[[1850,77860],[1900,575238],[1950,856796],[2020,301578]],
 eras:[
  {from:1764,to:1804,text:"Founded in February 1764 by Pierre Laclède and Auguste Chouteau as a French fur post, then administered by Spain as capital of Upper Louisiana while remaining French in language and custom. A British-led Indian attack was repulsed in 1780. In March 1804 the town saw three flags in two days as sovereignty passed from Spain to France to the United States."},
  {from:1804,to:1860,text:"Gateway to the West: Lewis and Clark left from nearby Camp Dubois in 1804 and returned here in 1806. The Chouteaus' fur empire, then steamboats from 1817, made the levee roar. German and Irish immigration surged; in 1849 cholera killed thousands and the Great Fire burned the riverfront. Dred Scott sued for freedom at the Old Courthouse."},
  {from:1860,to:1904,text:"A Union-held border city that lost the railroad race to Chicago but grew into the nation's fourth-largest city by 1900 on beer, shoes, and manufacturing. Eads Bridge spanned the Mississippi in 1874; the city split from its county in 1876. The 1904 World's Fair and Olympics crowned the era."},
  {from:1904,to:1980,text:"An industrial giant with hardening racial boundaries: a 1916 segregation ordinance, restrictive covenants struck down in Shelley v. Kraemer (1948, a St. Louis case). The Gateway Arch rose 1963-65 over the cleared riverfront. Pruitt-Igoe's demolition (1972-76) symbolized urban crisis as population plunged from its 1950 peak of 856,796."},
  {from:1980,to:2026,text:"Population fell to 301,578 by 2020, among the steepest declines of any major US city, while the metro area spread west. Universities, hospitals, biotech (the Cortex district), and brewing heritage anchor the economy; the 2014 Ferguson protests in suburban St. Louis County drew national attention to regional fragmentation."}
 ],
 sources:["U.S. Census Bureau, decennial census","Missouri Historical Society","National Park Service — Gateway Arch National Park"]},
{id:"washington",name:"Washington, D.C.",lon:-77.04,lat:38.90,founded:1790,appears:1790,joins:1790,tier:1,
 facts:[["Founded","1790, by the Residence Act"],["Role","Purpose-built national capital on the Potomac"],["Note","Enslaved and free Black laborers built the Capitol and White House"]],
 pop:[[1800,3210],[1850,40001],[1900,278718],[1950,802178],[2020,689545]],
 eras:[
  {from:1790,to:1814,text:"Created by the 1790 Residence Act on Maryland and Virginia land chosen by Washington; Pierre L'Enfant drew the plan and Benjamin Banneker helped survey it. Enslaved and free Black laborers built the Capitol and President's House. The government arrived from Philadelphia in 1800; in August 1814 British troops burned the public buildings."},
  {from:1814,to:1865,text:"Rebuilt but raw — a city of boardinghouses, mud avenues, and slave pens within sight of the Capitol until the 1850 Compromise banned the slave trade here. The Civil War made it a fortified Union nerve center swollen with soldiers and freedpeople; Congress emancipated the District's enslaved residents in April 1862, nine months before the Emancipation Proclamation."},
  {from:1865,to:1945,text:"Reconstruction brought Black political life, Howard University (1867), and brief territorial self-government before Congress imposed appointed commissioners in 1874, ending local suffrage. The McMillan Plan of 1901-02 shaped the monumental Mall. New Deal and wartime agencies swelled the federal workforce and the city."},
  {from:1945,to:1995,text:"Population peaked at 802,178 in 1950; by 1957 Washington was the first majority-Black major American city. The 1963 March on Washington filled the Mall; riots after King's assassination in 1968 scarred commercial corridors. The 1973 Home Rule Act restored an elected mayor and council under congressional oversight."},
  {from:1995,to:2026,text:"A federal control board ran city finances 1995-2001 after near-insolvency. Population and investment returned after 2000, gentrifying historically Black neighborhoods. On January 6, 2021 a mob stormed the Capitol to block the electoral count. Roughly 690,000 residents still lack voting representation in Congress; statehood remains contested."}
 ],
 sources:["U.S. Census Bureau, decennial census","Library of Congress","White House Historical Association","National Park Service"]},
{id:"pittsburgh",name:"Pittsburgh",lon:-79.99,lat:40.44,founded:1758,appears:1758,joins:1776,tier:2,
 facts:[["Founded","1758, at the Forks of the Ohio"],["Role","Steel capital of America"],["Note","Named for William Pitt when Forbes took Fort Duquesne, 1758"]],
 pop:[[1800,1565],[1850,46601],[1900,321616],[1950,676806],[2020,302971]],
 eras:[
  {from:1758,to:1794,text:"The contested Forks of the Ohio: France's Fort Duquesne fell to Forbes's British army in November 1758, which named the place for William Pitt and built Fort Pitt, besieged during Pontiac's War in 1763. A rough frontier village of traders and boatbuilders grew outside the walls; the Whiskey Rebellion climaxed nearby in 1794."},
  {from:1794,to:1865,text:"Outfitting point for settlers floating down the Ohio, then an early industrial town of glasshouses, foundries, and boatyards fueled by local coal. The Great Fire of 1845 destroyed a third of the city. During the Civil War its arsenals and mills armed the Union; the 1862 Allegheny Arsenal explosion killed 78 workers, mostly young women."},
  {from:1865,to:1945,text:"Carnegie, Frick, and Jones & Laughlin made this the world's steel capital, drawing Eastern European immigrants and Black Southern migrants to smoke-darkened mill valleys where streetlights sometimes burned at noon. The 1892 Homestead strike was crushed just upriver. Wartime output earned the region its arsenal-of-democracy reputation."},
  {from:1945,to:1985,text:"Renaissance I imposed smoke control and rebuilt the Point with Gateway Center. Big Steel then collapsed: imports and obsolete plants shut mill after mill in the late 1970s and early 1980s, erasing tens of thousands of jobs and emptying the Mon Valley towns around the city."},
  {from:1985,to:2026,text:"Universities and medicine — Pitt, Carnegie Mellon, UPMC — rebuilt the economy, later joined by robotics and autonomous-vehicle labs on former mill sites. Population settled near 303,000, less than half its 1950 peak, but the city became a national model for post-industrial reinvention."}
 ],
 sources:["U.S. Census Bureau, decennial census","Heinz History Center (Senator John Heinz History Center)","National Park Service — Fort Necessity National Battlefield"]},
{id:"cincinnati",name:"Cincinnati",lon:-84.51,lat:39.10,founded:1788,appears:1788,joins:1788,tier:2,
 facts:[["Founded","1788, as Losantiville on the Ohio"],["Role","Queen City of the West; pork-packing capital"],["First","First professional baseball team, the Red Stockings, 1869"]],
 pop:[[1810,2540],[1850,115435],[1900,325902],[1950,503998],[2020,309317]],
 eras:[
  {from:1788,to:1830,text:"Settled in 1788 opposite the Licking River and renamed for the Society of the Cincinnati in 1790, with Fort Washington anchoring campaigns against the Northwest Confederacy until the 1795 Treaty of Greenville. Flatboats, then steamboats after 1811, made it the young West's busiest river entrepot."},
  {from:1830,to:1870,text:"'Porkopolis,' the world's largest pork-packing center, and the self-styled Queen City of the West, with a huge German district in Over-the-Rhine. On the free bank opposite slaveholding Kentucky, it was an Underground Railroad crossing and Harriet Beecher Stowe's home, but white mobs attacked Black residents and abolitionists in 1829, 1836, and 1841. The Red Stockings turned professional in 1869."},
  {from:1870,to:1945,text:"Machine tools, soap (Procter & Gamble), playing cards, and beer replaced pork packing; Boss George Cox's machine ran city politics until Progressive reform. The 1937 Ohio River flood, the worst on record, drove tens of thousands from their homes and crested nearly 80 feet."},
  {from:1945,to:2026,text:"Interstate construction leveled the lower West End, displacing tens of thousands of mostly Black residents. Police shootings sparked civil unrest in Over-the-Rhine in 2001; the district was later heavily renovated. Procter & Gamble, Kroger, and GE Aerospace anchor a corporate economy along a redeveloped riverfront."}
 ],
 sources:["U.S. Census Bureau, decennial census","Cincinnati Museum Center","Encyclopaedia Britannica"]},
{id:"louisville",name:"Louisville",lon:-85.76,lat:38.25,founded:1778,appears:1778,joins:1778,tier:2,
 facts:[["Founded","1778, by George Rogers Clark at the Falls of the Ohio"],["Role","River portage city; bourbon and Derby town"],["Note","Kentucky Derby run at Churchill Downs since 1875"]],
 pop:[[1800,359],[1850,43194],[1900,204731],[1950,369129],[2020,633045]],
 eras:[
  {from:1778,to:1830,text:"George Rogers Clark planted settlers on Corn Island in 1778 as a base for his Illinois campaign; the town at the Falls of the Ohio was named in 1780 for Louis XVI, the Revolution's ally. Every cargo had to portage the falls, and the town lived on that trade until the Louisville and Portland Canal opened in 1830."},
  {from:1830,to:1900,text:"A slave-state river city trading tobacco, hemp, and enslaved people downriver, swelled by German and Irish immigrants; nativist 'Bloody Monday' riots killed at least 22 in 1855. Kentucky stayed in the Union and Louisville became a major supply base. The L&N Railroad reached south, and the first Kentucky Derby ran at Churchill Downs in 1875."},
  {from:1900,to:1970,text:"Tobacco warehouses, distilleries, and factories — later Ford plants and GE's Appliance Park — drove growth; wartime plants made synthetic rubber in 'Rubbertown.' The 1937 flood submerged most of the city and forced 175,000 evacuations. Muhammad Ali grew up here, and the city desegregated public accommodations earlier than most Southern peers."},
  {from:1970,to:2026,text:"Court-ordered busing in 1975 met violent protest in the county. UPS made the airport its Worldport global air hub, building a logistics economy. City and county merged in 2003, lifting population past 600,000. The 2020 police killing of Breonna Taylor made Louisville a center of national protest. Bourbon tourism boomed."}
 ],
 sources:["U.S. Census Bureau, decennial census","Filson Historical Society","Encyclopaedia Britannica"]},
{id:"chicago",name:"Chicago",lon:-87.63,lat:41.88,founded:1833,appears:1803,joins:1803,tier:1,
 facts:[["Founded","Town platted 1833; Fort Dearborn 1803"],["Role","Rail, grain, and industrial capital of the interior"],["Note","Du Sable, of African descent, settled the river mouth by the 1780s"]],
 pop:[[1840,4470],[1870,298977],[1900,1698575],[1950,3620962],[2020,2746388]],
 eras:[
  {from:1803,to:1833,text:"'Checagou,' the wild-garlic portage between the Great Lakes and Mississippi watersheds, was Potawatomi country; Jean Baptiste Point du Sable, of African descent, farmed the river mouth by the 1780s. The Army built Fort Dearborn in 1803; it was destroyed in the 1812 battle and rebuilt in 1816. The 1833 Treaty of Chicago forced Potawatomi cession and removal west."},
  {from:1833,to:1871,text:"Platted in 1833 with about 350 residents, the town exploded as canal (1848) and a web of railroads made it the grain, lumber, and meat market of the continent — nearly 300,000 people by 1870. On October 8-10, 1871 the Great Fire destroyed over three square miles, killed about 300, and left 100,000 homeless."},
  {from:1871,to:1945,text:"Rebuilt in steel and stone: the skyscraper was born here (Home Insurance Building, 1885). Haymarket (1886) and Pullman (1894) made it the storm center of American labor. The 1893 World's Columbian Exposition drew millions; engineers reversed the river in 1900. The Union Stock Yards, Great Migration, and the 1919 race riot shaped an industrial colossus."},
  {from:1945,to:1990,text:"Population peaked at 3.62 million in 1950. Richard J. Daley's machine (1955-76) built expressways, O'Hare, and vast segregated public housing; the 1968 Democratic convention brought police violence before cameras. Steel and stockyards closed as the Sears Tower (1973) briefly stood tallest on earth. Harold Washington became the first Black mayor in 1983."},
  {from:1990,to:2026,text:"The Loop, lakefront, and O'Hare hub economy boomed — Millennium Park opened 2004 — while South and West Side disinvestment, population loss, and gun violence persisted. Finance and derivatives trading, universities, and corporate headquarters keep it the interior's metropolis; 2.746 million counted in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Chicago History Museum","Encyclopedia of Chicago (Chicago History Museum and Newberry Library)"]},
{id:"detroit",name:"Detroit",lon:-83.05,lat:42.33,founded:1701,appears:1750,joins:1783,tier:1,
 facts:[["Founded","1701, by Cadillac as Fort Pontchartrain du Détroit"],["Role","The Motor City; arsenal of democracy"],["Note","Remained under British control until 1796 despite the 1783 treaty"]],
 pop:[[1820,1422],[1850,21019],[1900,285704],[1950,1849568],[2020,639111]],
 eras:[
  {from:1750,to:1796,text:"A French fur post founded by Cadillac in 1701 on the strait, surrounded by Odawa, Ojibwe, Potawatomi, and Wyandot communities. Britain took it in 1760; Pontiac besieged it in 1763. Though the 1783 treaty assigned it to the United States, the British garrison stayed until the Jay Treaty handover of July 1796."},
  {from:1796,to:1860,text:"Fire leveled nearly the whole town in 1805, and Judge Woodward's baroque street plan rose from the ashes. Surrendered to Britain in 1812, retaken in 1813. Capital of Michigan until 1847, it prospered on Great Lakes shipping, stoves, and shipbuilding, and served as the final Underground Railroad station before Canada, code-named 'Midnight.'"},
  {from:1860,to:1945,text:"Carriage and stove shops taught the skills that made the Motor City: Ford's Model T (1908) and five-dollar day (1914), then General Motors and Chrysler. The Great Migration multiplied the Black population into segregated neighborhoods; a 1943 race riot killed 34. Wartime plants earned Detroit the 'arsenal of democracy' name."},
  {from:1945,to:1990,text:"Population peaked at 1.85 million in 1950, then freeways, urban renewal that razed Black Bottom and Paradise Valley, and white flight hollowed the city. The July 1967 rebellion left 43 dead, among the worst civil disorders in US history. Coleman Young, elected 1973, became the first Black mayor as auto plants closed."},
  {from:1990,to:2026,text:"Decline bottomed out in the nation's largest municipal bankruptcy, filed 2013 with about 18 billion dollars in obligations. Downtown and Midtown revived with new investment while vast neighborhoods stayed depopulated — 639,111 residents in 2020, a third of the peak. The Big Three's electric-vehicle transition now shapes its prospects."}
 ],
 sources:["U.S. Census Bureau, decennial census","Detroit Historical Society","Library of Congress"]},
{id:"cleveland",name:"Cleveland",lon:-81.69,lat:41.50,founded:1796,appears:1796,joins:1796,tier:2,
 facts:[["Founded","1796, surveyed by Moses Cleaveland"],["Role","Iron, oil, and steel port on Lake Erie"],["Note","John D. Rockefeller founded Standard Oil here, 1870"]],
 pop:[[1850,17034],[1900,381768],[1950,914808],[2020,372624]],
 eras:[
  {from:1796,to:1832,text:"Moses Cleaveland's party surveyed the townsite for the Connecticut Land Company in 1796 on the Western Reserve at the malarial Cuyahoga mouth; growth was slow until the Ohio and Erie Canal, completed to the river in 1827-1832, made it the transfer point between lake and canal commerce."},
  {from:1832,to:1900,text:"Lake Superior iron ore met Appalachian coal on its docks, building iron, steel, and shipbuilding industries worked by German, Irish, and later Eastern European immigrants. John D. Rockefeller organized Standard Oil here in 1870, briefly making Cleveland the center of American oil refining."},
  {from:1900,to:1970,text:"By 1920 the nation's fifth-largest city, a steel and machine-tool power with the Van Sweringens' Terminal Tower (1930) crowning Public Square. Carl Stokes won election in 1967 as the first Black mayor of a major American city. The Hough uprising of 1966 and the June 1969 Cuyahoga River fire signaled industrial and civic strain."},
  {from:1970,to:2026,text:"In 1978 Cleveland became the first major city since the Depression to default on its debts; steel and population kept falling, to 372,624 by 2020 from a 1950 peak of 914,808. The Cleveland Clinic grew into the region's economic anchor, joined by the Rock and Roll Hall of Fame (1995) on a rebuilt lakefront."}
 ],
 sources:["U.S. Census Bureau, decennial census","Western Reserve Historical Society","Encyclopedia of Cleveland History (Case Western Reserve University)"]},
{id:"buffalo",name:"Buffalo",lon:-78.88,lat:42.89,founded:1804,appears:1804,joins:1804,tier:2,
 facts:[["Founded","1804, laid out by the Holland Land Company"],["Role","Erie Canal terminus; world's greatest grain port"],["First","World's first steam-powered grain elevator, 1843"]],
 pop:[[1850,42261],[1900,352387],[1950,580132],[2020,278349]],
 eras:[
  {from:1804,to:1832,text:"Joseph Ellicott laid out the village for the Holland Land Company in 1804 near Seneca communities of the Niagara frontier. British and Native forces burned it nearly to the ground in December 1813. Its fortune arrived in 1825 when the Erie Canal chose Buffalo as its western terminus; the city incorporated in 1832."},
  {from:1832,to:1901,text:"Where lake boats met the canal, Buffalo became the world's greatest grain-transfer port after Joseph Dart's steam elevator of 1843, the first anywhere. A key Underground Railroad crossing to Canada, then a rail and iron center powered by Niagara's new hydroelectricity (1896). At the 1901 Pan-American Exposition, President McKinley was shot; Theodore Roosevelt took the oath here."},
  {from:1901,to:1959,text:"Lackawanna steel, flour milling, chemicals, and Curtiss aircraft — P-40s rolled out here in World War II — made a blue-collar powerhouse of 580,132 people by 1950, heavily Polish, Italian, Irish, and, after the Great Migration, Black. The St. Lawrence Seaway opened in 1959, letting ocean ships bypass the port entirely."},
  {from:1959,to:2026,text:"The Seaway and steel's collapse — Bethlehem's Lackawanna works shut its main operations by 1983 — halved the population to 278,349 in 2020. Blizzards of 1977 and 2022 tested the city. A medical campus, universities, waterfront rebuilding at Canalside, and cheap Niagara power anchor a slow stabilization."}
 ],
 sources:["U.S. Census Bureau, decennial census","Buffalo History Museum","National Park Service — Theodore Roosevelt Inaugural National Historic Site"]},
{id:"sanfrancisco",name:"San Francisco",lon:-122.42,lat:37.77,founded:1776,appears:1776,joins:1848,tier:1,
 facts:[["Founded","1776, Spanish Presidio and Mission"],["Role","Gold Rush port; Pacific financial and tech capital"],["Note","Village of Yerba Buena renamed San Francisco, January 1847"]],
 pop:[[1860,56802],[1900,342782],[1950,775357],[2020,873965]],
 eras:[
  {from:1776,to:1848,text:"Spain planted the Presidio and Mission San Francisco de Asis in 1776 on Ramaytush Ohlone land; mission life devastated Native communities through disease and forced labor. Under Mexico after 1821, the trading hamlet of Yerba Buena grew by the cove from 1835. US forces raised the flag in July 1846, and the town took the name San Francisco in January 1847."},
  {from:1848,to:1906,text:"Gold, found January 1848 at Coloma, turned a village of under 1,000 into a port of about 25,000 within two years — the 'instant city' of forty-niners, merchant kings, and vigilance committees (1851, 1856). Comstock silver built its banks; cable cars climbed from 1873. Chinatown, the largest Chinese community outside Asia, endured exclusion-era violence and the 1882 Exclusion Act."},
  {from:1906,to:1945,text:"On April 18, 1906 a great earthquake and three days of fire destroyed some 28,000 buildings and killed an estimated 3,000. The city rebuilt fast, staging the 1915 Panama-Pacific Exposition, then spanned the bay: Bay Bridge 1936, Golden Gate 1937. A violent 1934 waterfront strike became a citywide general strike; World War II made it the Pacific embarkation port."},
  {from:1945,to:1990,text:"The UN Charter was signed here in 1945. Beats in North Beach, the 1967 Summer of Love in the Haight, and an emerging gay political capital — Harvey Milk elected 1977, assassinated 1978 — defined successive eras, before AIDS devastated the city in the 1980s. The Loma Prieta earthquake struck in 1989."},
  {from:1990,to:2026,text:"Dot-com, social-media, and AI booms concentrated extraordinary wealth; housing costs and homelessness became national symbols. The pandemic emptied downtown towers after 2020 even as artificial-intelligence firms clustered here. Population reached 873,965 in 2020 in a city of 47 square miles."}
 ],
 sources:["U.S. Census Bureau, decennial census","California Historical Society","National Park Service — Golden Gate National Recreation Area"]},
{id:"losangeles",name:"Los Angeles",lon:-118.24,lat:34.05,founded:1781,appears:1781,joins:1848,tier:1,
 facts:[["Founded","1781, Spanish pueblo on Tongva land"],["Role","Entertainment capital; largest US container port complex"],["Note","Owens Valley aqueduct water, 1913, enabled the modern city"]],
 pop:[[1850,1610],[1900,102479],[1950,1970358],[2020,3898747]],
 eras:[
  {from:1781,to:1848,text:"Founded September 4, 1781 as El Pueblo de la Reina de los Angeles by 44 settlers, most of African and Indigenous descent, beside the Tongva village of Yaangna. A Mexican rancho economy of cattle hides and tallow followed after 1821. US forces took the town in 1846-47; resistance ended with the Treaty of Cahuenga in January 1847."},
  {from:1848,to:1892,text:"A violent cattle town through the 1850s-60s; in 1871 a white and Latino mob lynched 18 or 19 Chinese residents, among the worst mass lynchings in US history. The Southern Pacific arrived in 1876, the Santa Fe in 1885, and their fare war set off the land boom of 1887. Citrus groves spread across the basin."},
  {from:1892,to:1945,text:"Oil strikes from 1892, the harbor annexed at San Pedro in 1909, and Mulholland's Owens Valley aqueduct in 1913 built a metropolis; Hollywood made it the world's film capital by the 1920s. Aircraft plants boomed in World War II while Japanese American residents were removed to camps in 1942 and servicemen attacked Mexican American youths in the 1943 Zoot Suit Riots."},
  {from:1945,to:1992,text:"The freeway metropolis: aerospace employment, suburban tracts, smog, and Dodger Stadium in Chavez Ravine, cleared of its Mexican American community. The Watts uprising of 1965 killed 34; the 1984 Olympics showcased a global city. In April-May 1992, acquittals in the Rodney King beating sparked six days of unrest and 63 deaths."},
  {from:1992,to:2026,text:"Rebuilt as a majority-Latino global city of entertainment, trade through the San Pedro Bay ports, and immigration from everywhere. The 1994 Northridge earthquake caused tens of billions in damage. Homelessness grew into the defining crisis; the January 2025 Palisades and Eaton fires were among the costliest in US history. The 2028 Olympics loom."}
 ],
 sources:["U.S. Census Bureau, decennial census","Los Angeles Public Library","Huntington Library","Encyclopaedia Britannica"]},
{id:"sandiego",name:"San Diego",lon:-117.16,lat:32.72,founded:1769,appears:1769,joins:1848,tier:2,
 facts:[["Founded","1769, first Spanish settlement in Alta California"],["Role","Navy town and border metropolis"],["Note","Kumeyaay revolt burned the mission in 1775"]],
 pop:[[1860,731],[1900,17700],[1950,334387],[2020,1386932]],
 eras:[
  {from:1769,to:1848,text:"Portola and Serra founded Alta California's first presidio and mission here in 1769 on Kumeyaay land; the Kumeyaay rose and burned the mission in 1775. A small Mexican pueblo formed below the hill after 1821, trading cattle hides to Boston ships — the world Richard Henry Dana described. US forces held it through the 1846 campaign."},
  {from:1848,to:1900,text:"A sleepy adobe village at Old Town until Alonzo Horton bought bayfront land in 1867 and moved the city to his New Town by the harbor. The 1880s railroad boom collapsed as quickly as it came; by 1900 the town counted fewer than 18,000 people living on whaling memories, fishing, and health-seeker tourism."},
  {from:1900,to:1945,text:"The 1915 Panama-California Exposition built Balboa Park's ornate pavilions and advertised the harbor to the Navy, which made San Diego a fleet and aviation base. Consolidated Aircraft moved here in 1935; its wartime B-24 lines and the naval training complex tripled the city in a decade."},
  {from:1945,to:2026,text:"The Cold War Navy and Marines made this the largest military complex on the West Coast; tuna fleets gave way to defense electronics, UC San Diego (1960), and a major biotech cluster. Twinned with Tijuana at the world's busiest land border crossing, San Diego reached 1.39 million people by 2020, second in California."}
 ],
 sources:["U.S. Census Bureau, decennial census","San Diego History Center","National Park Service — Cabrillo National Monument"]},
{id:"sacramento",name:"Sacramento",lon:-121.49,lat:38.58,founded:1839,appears:1839,joins:1848,tier:2,
 facts:[["Founded","1839, as Sutter's New Helvetia"],["Role","Gold Rush supply city; California's capital since 1854"],["Note","Western terminus of the Pony Express and first transcontinental railroad"]],
 pop:[[1860,13785],[1900,29282],[1950,137572],[2020,524943]],
 eras:[
  {from:1839,to:1848,text:"Swiss immigrant John Sutter built his fortified New Helvetia colony in 1839 on Nisenan and Plains Miwok lands under a Mexican grant, running it with coerced Native labor. Gold found at his Coloma sawmill in January 1848 destroyed his agricultural empire and summoned the world to the Sacramento Valley."},
  {from:1848,to:1870,text:"The city platted at Sutter's embarcadero in 1848 became the Gold Rush supply port — and suffered cholera in 1850 and catastrophic floods in 1850, 1852, and 1861-62, after which whole streets were raised a story. State capital from 1854, western terminus of the Pony Express in 1860, and home of the Big Four merchants who broke ground for the Central Pacific in 1863; the transcontinental railroad was done by 1869."},
  {from:1870,to:1950,text:"A railroad-shop town: the Central Pacific (later Southern Pacific) shops were the city's industrial heart, surrounded by canneries processing the valley's fruit. Levees and reclamation turned floodplain into farmland; state government grew steadily under the Capitol dome completed in 1874."},
  {from:1950,to:2026,text:"Cold War aerospace (Aerojet, McClellan and Mather air bases) boomed, then the 1990s base closures hit; state government and Sacramento's role as the valley's service center carried growth to 524,943 by 2020. Folsom Dam (1955) and rebuilt levees manage a flood risk still ranked among the nation's highest."}
 ],
 sources:["U.S. Census Bureau, decennial census","California State Library","Center for Sacramento History"]},
{id:"portland",name:"Portland",lon:-122.68,lat:45.52,founded:1845,appears:1845,joins:1846,tier:2,
 facts:[["Founded","1845, named by a coin flip"],["Role","Lumber and wheat port on the Willamette"],["Note","Oregon Treaty of 1846 placed it under US sovereignty"]],
 pop:[[1860,2874],[1900,90426],[1950,373628],[2020,652503]],
 eras:[
  {from:1845,to:1869,text:"Platted in 1845 in a clearing on Chinookan lands already emptied by the malaria epidemics of the 1830s, and named Portland over Boston by two coin tosses. The 1846 Oregon Treaty fixed US sovereignty. 'Stumptown' shipped lumber and wheat to Gold Rush California and became the Willamette's deep-water port."},
  {from:1869,to:1905,text:"Transcontinental rail connection in 1883 made Portland the Northwest's commercial capital until Seattle's rise. A large Chinatown endured exclusion-era harassment; the waterfront was notorious for crimping and 'shanghaiing' sailors. Wheat, salmon, and timber fortunes built cast-iron blocks and West Hills mansions."},
  {from:1905,to:1948,text:"The 1905 Lewis and Clark Exposition set off a decade of doubling growth. Oregon's exclusionary heritage persisted: the Klan wielded real state power in the 1920s. World War II brought Kaiser's shipyards and the instant workers' city of Vanport, home to much of the region's new Black population — destroyed by the May 1948 flood, which displaced 18,000."},
  {from:1948,to:2026,text:"Postwar planning made Portland a byword for urbanism: an urban growth boundary (1979), light rail (1986), and a razed riverfront freeway turned park. 'Silicon Forest' electronics grew in the suburbs. The 2020 racial-justice protests ran for months downtown. Population reached 652,503 in 2020 amid housing and homelessness strains."}
 ],
 sources:["U.S. Census Bureau, decennial census","Oregon Historical Society","Encyclopaedia Britannica"]},
{id:"seattle",name:"Seattle",lon:-122.33,lat:47.61,founded:1851,appears:1851,joins:1851,tier:1,
 facts:[["Founded","1851, on Duwamish land; named for Chief Si'ahl"],["Role","Klondike gateway; aerospace and software capital"],["Note","Great Fire of June 1889 leveled the business district"]],
 pop:[[1880,3533],[1900,80671],[1950,467591],[2020,737015]],
 eras:[
  {from:1851,to:1889,text:"The Denny Party landed at Alki in November 1851, then moved to Elliott Bay on Duwamish land, naming the town for Chief Si'ahl (Seattle). Yesler's sawmill (1853) cut the first payrolls; the 1855 Treaty of Point Elliott was followed by the 1856 'Battle of Seattle.' A mob expelled most Chinese residents in 1886. On June 6, 1889 fire destroyed the entire business district."},
  {from:1889,to:1916,text:"Rebuilt in brick a story above the old streets, Seattle struck it rich outfitting Klondike gold-seekers from 1897 — population quadrupled to 237,000 by 1910. Engineers sluiced Denny Hill into the bay, and the ship canal and locks (1916-17) linked the lakes to Puget Sound."},
  {from:1916,to:1971,text:"Boeing, founded 1916, became the economy: B-17s and B-29s in World War II, then the jet age. The 1919 General Strike was the first citywide strike in US history; Japanese American neighbors were incarcerated in 1942. The 1962 World's Fair raised the Space Needle. When Boeing slashed jobs in 1969-71, a billboard asked the last person leaving to turn out the lights."},
  {from:1971,to:2026,text:"Microsoft (suburban Redmond, from 1979) and Amazon (founded here 1994) rebuilt Seattle as a software capital; grunge made it a 1990s cultural export, and the 1999 WTO protests filled downtown with tear gas. Amazon's headquarters remade whole districts. Population hit 737,015 in 2020; housing costs and homelessness rose with the boom."}
 ],
 sources:["U.S. Census Bureau, decennial census","Museum of History & Industry (MOHAI), Seattle","National Park Service — Klondike Gold Rush National Historical Park"]},
{id:"denver",name:"Denver",lon:-104.99,lat:39.74,founded:1858,appears:1858,joins:1858,tier:1,
 facts:[["Founded","1858, gold camp at Cherry Creek"],["Role","Queen City of the Plains; Rocky Mountain hub"],["Note","Silver Crash of 1893 nearly broke the young city"]],
 pop:[[1870,4759],[1900,133859],[1950,415786],[2020,715522]],
 eras:[
  {from:1858,to:1870,text:"Placer gold at the Cherry Creek-South Platte confluence in 1858 planted rival camps on land guaranteed to the Cheyenne and Arapaho by treaty; the 1861 Treaty of Fort Wise stripped most of it away, and in 1864 Colorado cavalry organized in Denver perpetrated the Sand Creek Massacre. Fire (1863) and flood (1864) nearly erased the town."},
  {from:1870,to:1893,text:"The Denver Pacific's 1870 link to the transcontinental line saved the city; smelters made it the processing capital of the Rockies' silver boom, and population passed 106,000 by 1890. An anti-Chinese riot destroyed Hop Alley in 1880. The 1893 repeal of silver purchase crashed mines, smelters, and banks together."},
  {from:1893,to:1945,text:"Recovery came as the plains' supply and rail center: stockyards, sugar beets, and Mayor Speer's City Beautiful parks and Civic Center. The Ku Klux Klan captured city and state politics in the mid-1920s before collapsing. Federal offices multiplied — a 'second Washington' — and wartime installations ringed the city."},
  {from:1945,to:2026,text:"Oil-shale and energy booms and busts alternated with steady federal, aerospace, and airport growth; Denver International opened in 1995 on the prairie. The 'brown cloud' smog of the 1970s-80s spurred cleanup. Marijuana legalization (2012), a tech influx, and Front Range sprawl carried the city to 715,522 people by 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","History Colorado","Denver Public Library, Western History Collection"]},
{id:"saltlakecity",name:"Salt Lake City",lon:-111.89,lat:40.76,founded:1847,appears:1847,joins:1848,tier:2,
 facts:[["Founded","1847, by Latter-day Saint pioneers"],["Role","Headquarters of the LDS Church; crossroads of the West"],["Note","Founded on land still nominally Mexican, ceded to the US in 1848"]],
 pop:[[1860,8236],[1900,53531],[1950,182121],[2020,199723]],
 eras:[
  {from:1847,to:1869,text:"Brigham Young's pioneers arrived July 24, 1847, planting a gridded refuge city at Temple Square on Shoshone and Ute borderlands then still nominally Mexican; the 1848 Treaty of Guadalupe Hidalgo made it American. Irrigated farming, the provisional State of Deseret (1849), Utah Territory (1850), and the 1857-58 Utah War with federal troops marked its first decades."},
  {from:1869,to:1896,text:"The transcontinental railroad (1869) brought non-Mormon merchants, miners, and federal power. The temple was completed in 1893 after forty years. Federal anti-polygamy campaigns — the Edmunds and Edmunds-Tucker Acts — jailed leaders and seized church property until the 1890 Manifesto opened the way to statehood in 1896."},
  {from:1896,to:1960,text:"Capital of the new state and headquarters of the Latter-day Saint church, ringed by a mining and smelting economy: Bingham Canyon's vast open-pit copper mine (from 1906) and valley smelters. Fort Douglas, rail yards, and wartime industry diversified a city that stayed compact beside its growing suburbs."},
  {from:1960,to:2026,text:"Church administration, genealogy, and finance grew alongside ski tourism — the 2002 Winter Olympics were staged here — and the 'Silicon Slopes' tech corridor to the south. Population held near 200,000 within a booming metro. The shrinking Great Salt Lake, at record lows in 2022, became the region's defining environmental threat."}
 ],
 sources:["U.S. Census Bureau, decennial census","Utah State Historical Society","Encyclopaedia Britannica"]},
{id:"santafe",name:"Santa Fe",lon:-105.94,lat:35.69,founded:1610,appears:1750,joins:1848,tier:2,
 facts:[["Founded","1610, capital of Spanish Nuevo México"],["Role","Oldest US state capital; end of the Santa Fe Trail"],["Note","Pueblo Revolt of 1680 expelled the Spanish for twelve years"]],
 pop:[[1850,4846],[1900,5603],[1950,27998],[2020,87505]],
 eras:[
  {from:1750,to:1821,text:"Capital of Spanish Nuevo México, founded 1610 by Pedro de Peralta around the Palace of the Governors — already recovered from the 1680 Pueblo Revolt that had expelled the Spanish for twelve years. A garrison and mission town among the Pueblos, raided by and trading with Comanche and Apache until the 1786 Comanche peace, and closed by law to foreign commerce."},
  {from:1821,to:1848,text:"Mexican independence in 1821 opened the Santa Fe Trail to Missouri, and the plaza filled with American wagon freight and silver. Governor Perez was killed in the 1837 revolt. In August 1846 Kearny's Army of the West marched in without a battle, and the Treaty of Guadalupe Hidalgo confirmed US rule in 1848."},
  {from:1848,to:1912,text:"US territorial capital and Army supply center; Bishop Lamy raised a French Romanesque cathedral over the adobe town. The main railroad line bypassed the city in 1880, leaving only a spur, and commerce stagnated while territorial politics — the Santa Fe Ring — thrived. Statehood finally came in 1912, making this the oldest US state capital."},
  {from:1912,to:2026,text:"Reinvented as an art and heritage capital: museums, the Indian Market (from 1922), and a 1957 ordinance mandating adobe-revival style. In 1943 the Manhattan Project ran its secret Los Alamos office at 109 East Palace. State government and tourism sustain a city of 87,505 (2020) that trades on four centuries of layered Pueblo, Spanish, Mexican, and American history."}
 ],
 sources:["U.S. Census Bureau, decennial census","New Mexico History Museum / Palace of the Governors","National Park Service"]},
{id:"sanantonio",name:"San Antonio",lon:-98.49,lat:29.42,founded:1718,appears:1750,joins:1845,tier:2,
 facts:[["Founded","1718, Spanish presidio and Mission San Antonio de Valero"],["Role","Capital of Spanish Texas; Military City USA"],["Note","The Alamo fell here, March 6, 1836"]],
 pop:[[1850,3488],[1900,53321],[1950,408442],[2020,1434625]],
 eras:[
  {from:1750,to:1821,text:"A Spanish presidio, the villa of San Fernando settled by Canary Islanders in 1731, and five river missions — including San Antonio de Valero, the later Alamo — built to convert Coahuiltecan peoples. Capital of Spanish Texas from 1773, it endured Apache and Comanche warfare and was bloodily contested in the 1813 Gutierrez-Magee rebellion."},
  {from:1821,to:1845,text:"Under Mexico, the Tejano town watched Anglo colonization spread east. Revolution came home: rebels took the city in the December 1835 Siege of Bexar, and Santa Anna's army stormed the Alamo on March 6, 1836, killing its roughly 190 defenders. Raided twice by Mexican armies in 1842, it remained a frontier outpost of the Texas Republic until US annexation."},
  {from:1845,to:1900,text:"Annexation in 1845 brought the US Army, which made San Antonio its Texas depot — Fort Sam Houston rose in the 1870s. German immigrants, Tejano freighters, and cattle-trail commerce mixed on its plazas; the railroad's arrival in 1877 ended isolation, and by 1900 this was Texas's largest city, 53,321 people."},
  {from:1900,to:1968,text:"A military city: Kelly Field trained World War I aviators, and five bases anchored the economy through World War II. A deadly 1921 flood led to the Olmos Dam and, in 1939-41, WPA construction of the River Walk. Segregated west-side barrios suffered notorious poverty; pecan-sheller strikes in 1938 marked Mexican American labor militancy. HemisFair '68 celebrated 250 years."},
  {from:1968,to:2026,text:"Military medicine, tourism, and Toyota manufacturing carried growth past 1.43 million by 2020, seventh among US cities and majority-Hispanic. Henry Cisneros's 1981 election made him the first Mexican American mayor of a major modern US city. The Alamo and missions, named a World Heritage site in 2015, draw millions yearly."}
 ],
 sources:["U.S. Census Bureau, decennial census","Texas State Historical Association","National Park Service — San Antonio Missions National Historical Park"]},
{id:"houston",name:"Houston",lon:-95.37,lat:29.76,founded:1836,appears:1836,joins:1845,tier:1,
 facts:[["Founded","1836, by the Allen brothers on Buffalo Bayou"],["Role","Energy capital; home of Mission Control"],["Note","Ship Channel (1914) made an inland city a great port"]],
 pop:[[1850,2396],[1900,44633],[1950,596163],[2020,2304580]],
 eras:[
  {from:1836,to:1861,text:"The Allen brothers platted a speculative townsite on swampy Buffalo Bayou in August 1836, weeks after San Jacinto, and named it for the victor. Capital of the Texas Republic 1837-39, it survived yellow fever and mud as a cotton depot where enslaved labor moved bales toward Galveston; annexation made it American in 1845, and railroads radiated out by 1860."},
  {from:1861,to:1914,text:"A Confederate interior depot, then a rail hub that seized its chance when the 1900 hurricane wrecked rival Galveston. Spindletop's 1901 gusher near Beaumont birthed the Texas oil industry, and Houston built the refineries. The dredged Houston Ship Channel opened to deep-water traffic in 1914, making an inland prairie town a seaport."},
  {from:1914,to:1970,text:"Oil refining and petrochemicals lined the channel; wartime synthetic rubber and shipbuilding, then air conditioning, fueled unzoned sprawl. NASA's Manned Spacecraft Center arrived in the early 1960s — 'Houston' was the first word radioed from the Moon in 1969. The Astrodome, the self-styled Eighth Wonder, opened in 1965."},
  {from:1970,to:2026,text:"The 1970s oil boom and 1980s bust taught diversification: the Texas Medical Center grew into the world's largest medical complex, and the metro became one of America's most diverse. Floods define its geography — Tropical Storm Allison (2001), then Hurricane Harvey (2017) with roughly 50 inches of rain. 2,304,580 people in 2020, fourth among US cities."}
 ],
 sources:["U.S. Census Bureau, decennial census","Texas State Historical Association","NASA Johnson Space Center"]},
{id:"dallas",name:"Dallas",lon:-96.80,lat:32.78,founded:1841,appears:1841,joins:1845,tier:2,
 facts:[["Founded","1841, John Neely Bryan's Trinity River trading post"],["Role","Cotton, banking, and oil-money metropolis"],["Note","President Kennedy assassinated at Dealey Plaza, 1963"]],
 pop:[[1880,10358],[1900,42638],[1950,434462],[2020,1304379]],
 eras:[
  {from:1841,to:1873,text:"John Neely Bryan staked a trading post and ferry on the Trinity in 1841, in country from which the Caddo had recently been driven. A courthouse village of the Peters Colony, joined in 1855 by artisans from the failed French utopian colony La Reunion, it schemed successfully to capture two rail lines, which crossed here in 1872-73 and set off an instant boom."},
  {from:1873,to:1930,text:"The rail crossing made Dallas the cotton market of North Texas and a wholesale, insurance, and banking center — a Federal Reserve Bank arrived in 1914. Skyscrapers rose over the blackland prairie. The 1920s brought both civic boosterism and one of the nation's largest Ku Klux Klan chapters."},
  {from:1930,to:1963,text:"The 1930 East Texas oil strike made Dallas the money center of the mid-continent fields; the 1936 Texas Centennial Exposition built Fair Park's Art Deco campus. Wartime aviation plants seeded an electronics industry — Texas Instruments invented the integrated circuit here in 1958. On November 22, 1963 President Kennedy was assassinated at Dealey Plaza."},
  {from:1963,to:2026,text:"Determined to outgrow its 'city of hate' label, Dallas built DFW Airport (1974) with Fort Worth and boomed on banking, telecom, and corporate relocations; TV's 'Dallas' broadcast its oil image worldwide. A 2016 sniper attack killed five police officers downtown. The city reached 1,304,379 in 2020 at the core of a metroplex approaching eight million."}
 ],
 sources:["U.S. Census Bureau, decennial census","Texas State Historical Association","Dallas Historical Society"]},
{id:"austin",name:"Austin",lon:-97.74,lat:30.27,founded:1839,appears:1839,joins:1845,tier:2,
 facts:[["Founded","1839, chosen as capital of the Republic of Texas"],["Role","Texas capital; university and tech city"],["Note","Named for Stephen F. Austin; site was the hamlet of Waterloo"]],
 pop:[[1880,11013],[1900,22258],[1950,132459],[2020,961855]],
 eras:[
  {from:1839,to:1861,text:"The Republic of Texas planted its capital in 1839 at the frontier hamlet of Waterloo on the Colorado River, renaming it for Stephen F. Austin — a deliberately exposed site on the Comanche frontier. Sam Houston tried to remove the government archives in 1842; armed citizens kept them. Annexation in 1845 made it a state capital, confirmed by later elections."},
  {from:1861,to:1900,text:"Travis County voted against secession in 1861, though the city passed the war under the Confederacy. The railroad arrived in 1871, the University of Texas opened in 1883, and the massive pink-granite Capitol was dedicated in 1888. An ambitious dam on the Colorado, finished 1893, collapsed in the flood of April 1900."},
  {from:1900,to:1970,text:"A government and university town. The 1928 city plan pushed Black residents into East Austin by locating segregated services there — a boundary that shaped the city for generations. New Deal dams built by the LCRA finally tamed the Colorado and lit the Hill Country. In 1966 a sniper atop the UT Tower killed more than a dozen people."},
  {from:1970,to:2026,text:"Tech arrived — IBM, Motorola, then Michael Dell's company in 1984 — while the music scene of the Armadillo era branded the 'Live Music Capital'; South by Southwest began in 1987. Among the fastest-growing big US cities every decade since, Austin passed 961,000 by 2020, gaining Tesla's headquarters in 2021 and severe affordability strains."}
 ],
 sources:["U.S. Census Bureau, decennial census","Texas State Historical Association","Austin History Center, Austin Public Library"]},
{id:"galveston",name:"Galveston",lon:-94.80,lat:29.30,founded:1839,appears:1839,joins:1845,tier:3,
 facts:[["Founded","1839, incorporated on Galveston Island"],["Role","Great 19th-century Texas port; birthplace of Juneteenth"],["Note","The 1900 hurricane remains the deadliest US natural disaster"]],
 pop:[[1850,4177],[1900,37789],[1950,66568],[2020,53695]],
 eras:[
  {from:1839,to:1861,text:"Laid out on an island that had held Karankawa camps and Jean Lafitte's pirate base of Campeche (1817-21), Galveston incorporated in 1839 and became the Republic's — then the state's — premier port and largest city: cotton wharves, merchant houses, immigrants landing, and the principal slave market of Texas."},
  {from:1861,to:1900,text:"Confederates retook the blockaded port in the Battle of Galveston, January 1, 1863. On June 19, 1865 General Granger's General Order No. 3 announced emancipation here — the origin of Juneteenth. The Gilded Age made the Strand the 'Wall Street of the South,' with Texas's first electric lights and a deep-water harbor by 1896."},
  {from:1900,to:1957,text:"The hurricane of September 8, 1900 killed an estimated 6,000 to 8,000 people, the deadliest natural disaster in US history. The city invented commission government to rebuild, raised the island grade, and built a 17-foot seawall — but Houston took the port trade. The Maceo syndicate's casinos ran an 'open secret' vice economy until Texas Rangers shut it down in 1957."},
  {from:1957,to:2026,text:"A slower island city of insurance firms, the University of Texas Medical Branch, shrimping, and historic-district tourism on the Strand; cruise ships became a mainstay. Hurricane Ike flooded most of the island in 2008. Juneteenth, born here, became a federal holiday in 2021, with Galveston at the center of its commemoration."}
 ],
 sources:["U.S. Census Bureau, decennial census","Texas State Historical Association","Rosenberg Library, Galveston"]},
{id:"memphis",name:"Memphis",lon:-90.05,lat:35.15,founded:1819,appears:1819,joins:1819,tier:2,
 facts:[["Founded","1819, on the Fourth Chickasaw Bluff"],["Role","Cotton market; home of the blues; logistics hub"],["Note","Dr. Martin Luther King Jr. assassinated here, April 4, 1968"]],
 pop:[[1850,8841],[1900,102320],[1950,396000],[2020,633104]],
 eras:[
  {from:1819,to:1865,text:"Founded in 1819 by speculators including Andrew Jackson on the Fourth Chickasaw Bluff, opened by the 1818 Chickasaw cession. Steamboats made it the mid-South's cotton market and one of the largest slave-trading centers on the river — Nathan Bedford Forrest ran a slave mart here. A Union fleet took the city in the June 1862 naval battle."},
  {from:1865,to:1900,text:"In May 1866 white mobs, including police, killed some 46 Black residents in the Memphis Massacre. Yellow fever struck in 1873 and catastrophically in 1878, killing over 5,000 and so emptying the city that its charter was revoked in 1879. Recovery came on cotton, hardwood lumber, and the pure artesian water discovered in 1887."},
  {from:1900,to:1968,text:"Beale Street became the Black main street of the mid-South; W.C. Handy published the blues here, and Boss E.H. Crump's machine ruled politics for decades. Clarence Saunders opened Piggly Wiggly, the first self-service grocery, in 1916. Sun Studio recorded Elvis Presley and B.B. King in the 1950s. On April 4, 1968, during the sanitation workers' strike, Dr. King was assassinated at the Lorraine Motel."},
  {from:1968,to:2026,text:"FedEx, founded here in the early 1970s, made Memphis International the world's busiest cargo airport for most years since, anchoring a distribution economy. The National Civil Rights Museum opened at the Lorraine Motel in 1991; Graceland draws pilgrims. A majority-Black city of 633,104 (2020), it remains the mid-South's medical and logistics center."}
 ],
 sources:["U.S. Census Bureau, decennial census","Tennessee State Library and Archives","National Civil Rights Museum"]},
{id:"nashville",name:"Nashville",lon:-86.78,lat:36.16,founded:1779,appears:1779,joins:1779,tier:2,
 facts:[["Founded","1779-80, as Fort Nashborough on the Cumberland"],["Role","Athens of the South; capital of country music"],["Note","1960 sit-ins made it the first major Southern city to desegregate lunch counters"]],
 pop:[[1850,10165],[1900,80865],[1950,174307],[2020,689447]],
 eras:[
  {from:1779,to:1843,text:"The Robertson and Donelson parties founded Fort Nashborough in the winter of 1779-80 on Cumberland River land contested by Cherokee and Chickasaw hunters; the Battle of the Bluffs came in 1781. Named for General Francis Nash, the river town grew on tobacco, cotton, and enslaved labor, and was fixed as Tennessee's permanent capital in 1843."},
  {from:1843,to:1880,text:"William Strickland's Greek Revival Capitol rose 1845-59, built partly with enslaved and convict labor. In February 1862 Nashville became the first Confederate state capital to fall, and the December 1864 Battle of Nashville shattered Hood's army. Fisk University opened for freedpeople in 1866; its Jubilee Singers toured the world from 1871."},
  {from:1880,to:1950,text:"The 'Athens of the South': Vanderbilt, Fisk, Meharry, and a full-scale Parthenon built for the 1897 centennial exposition. Insurance firms, religious publishing houses, and banks drove commerce. In 1925 WSM radio launched the barn dance that became the Grand Ole Opry, planting the seed of the country-music industry."},
  {from:1950,to:2026,text:"Music Row and the Opry made Nashville country music's capital. Disciplined student sit-ins in 1960 — Lewis, Nash, Lawson — desegregated lunch counters ahead of other major Southern cities. City and county consolidated in 1963, a national first among major cities. Healthcare corporations (HCA, 1968) and a 2010s boom carried the 'It City' to 689,447 people in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Tennessee State Museum","Country Music Hall of Fame and Museum"]},
{id:"atlanta",name:"Atlanta",lon:-84.39,lat:33.75,founded:1837,appears:1837,joins:1837,tier:1,
 facts:[["Founded","1837, as the rail terminus called Terminus"],["Role","Rail crossroads reborn as the capital of the Black South"],["Note","Burned by Sherman's forces, November 1864"]],
 pop:[[1860,9554],[1900,89872],[1950,331314],[2020,498715]],
 eras:[
  {from:1837,to:1864,text:"Staked in 1837 as Terminus, the end of the Western & Atlantic Railroad, on lands taken from Creek and Cherokee peoples in the removal era; renamed Marthasville, then Atlanta by 1847. By the Civil War the rail junction was the Confederacy's transport and munitions crossroads — besieged through the summer of 1864, captured September 2, and largely burned that November."},
  {from:1864,to:1906,text:"Rebuilt under the motto Resurgens; Henry Grady preached a commercial 'New South' while Coca-Cola was first served here in 1886. Atlanta University, Morehouse, and Spelman made it the capital of Black higher education, and W.E.B. Du Bois wrote here. In September 1906 white mobs killed dozens of Black residents in the Atlanta race massacre."},
  {from:1906,to:1961,text:"Auburn Avenue thrived as one of America's most prosperous Black business districts — Martin Luther King Jr. was born on it in 1929. The 1917 fire burned 300 acres. Mayor Hartsfield bet the city on aviation from 1925 and coined 'the city too busy to hate' as Atlanta brokered a calmer image through school desegregation in 1961."},
  {from:1961,to:1996,text:"Headquarters of King's SCLC and the civil-rights movement's strategic capital. Maynard Jackson's 1973 election began an unbroken line of Black mayors; his airport expansion and minority-contracting policies built Black wealth as Hartsfield grew toward busiest-in-the-world status. CNN launched in 1980. The 1996 Centennial Olympics remade downtown despite the park bombing."},
  {from:1996,to:2026,text:"Core of a metro past six million: Delta, Coca-Cola, and the world's busiest airport, plus a dominant film-production industry after 2010 tax credits. The BeltLine converted rail rings to trails and development. The city proper counted 498,715 in 2020, its influence as a Black political and cultural capital far exceeding its size."}
 ],
 sources:["U.S. Census Bureau, decennial census","Atlanta History Center","National Park Service — Martin Luther King Jr. National Historical Park"]},
{id:"miami",name:"Miami",lon:-80.19,lat:25.76,founded:1896,appears:1896,joins:1896,tier:1,
 facts:[["Founded","1896, incorporated when Flagler's railroad arrived"],["Role","Gateway to Latin America"],["Note","Julia Tuttle, the 'Mother of Miami,' recruited the railroad"]],
 pop:[[1900,1681],[1920,29571],[1950,249276],[2020,442241]],
 eras:[
  {from:1896,to:1926,text:"Julia Tuttle lured Henry Flagler's Florida East Coast Railway to Biscayne Bay in 1896, and the city incorporated that July — many of its 368 charter voters Black laborers, a large share Bahamian — on ground the Tequesta had occupied for centuries. The 1920s land boom ran wild until the 1926 hurricane and bust flattened it."},
  {from:1926,to:1959,text:"Depression came early, but Miami Beach's Art Deco hotel rows rose through the 1930s. World War II filled hotels with servicemen in training, and veterans returned as residents; postwar air routes, air conditioning, and retirees pushed the 1950 population past 249,000."},
  {from:1959,to:1992,text:"The Cuban Revolution of 1959 sent waves of exiles who remade Miami — the Freedom Tower processed arrivals — followed by the 1980 Mariel boatlift the same year the McDuffie verdict sparked deadly riots. Cocaine money and violence marked the 1980s even as the city became the banking and trade gateway to Latin America. Hurricane Andrew struck south of downtown in August 1992."},
  {from:1992,to:2026,text:"A hemispheric capital of trade, banking, art (Art Basel from 2002), and Spanish-language media, with relentless condo booms. Sea-level rise brought routine sunny-day flooding and the country's most explicit climate-adaptation politics. Finance and crypto migrations after 2020 lifted prices; the city proper counted 442,241 residents in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","HistoryMiami Museum","Encyclopaedia Britannica"]},
{id:"tampa",name:"Tampa",lon:-82.46,lat:27.95,founded:1824,appears:1824,joins:1824,tier:3,
 facts:[["Founded","1824, around Fort Brooke"],["Role","Cigar City; Gulf port"],["Note","Ybor City made it the Cigar Capital of the World"]],
 pop:[[1880,720],[1900,15839],[1950,124681],[2020,384959]],
 eras:[
  {from:1824,to:1885,text:"Fort Brooke, established January 1824 at the Hillsborough River's mouth on former Tocobaga and contested Seminole country, staged troops and removals through the Seminole Wars. A small village of fishermen, cattlemen shipping to Cuba, and traders clung to the fort through yellow fever and the Civil War blockade; barely 720 people lived here in 1880."},
  {from:1885,to:1945,text:"Vicente Martinez-Ybor moved his cigar factories from Key West in 1885-86, and Ybor City's Cuban, Spanish, and Italian workers — with their mutual-aid societies and lectors — made Tampa the Cigar Capital of the World. Henry Plant's railroad and 1891 Tampa Bay Hotel opened tourism; Jose Marti organized Cuban independence here, and troops embarked for the 1898 war. Phosphate moved through the port."},
  {from:1945,to:2026,text:"Machine-made cigars and mechanization shrank the hand-rolling trade; MacDill Air Force Base grew into headquarters for US Central Command. The port, banking, and bay-area sprawl drove growth to 384,959 in 2020. The Gasparilla pirate festival, Ybor's historic district, and repeated hurricane near-misses (and hits, 2024) mark civic life."}
 ],
 sources:["U.S. Census Bureau, decennial census","Tampa Bay History Center","Florida State Archives"]},
{id:"kansascity",name:"Kansas City",lon:-94.58,lat:39.10,founded:1838,appears:1838,joins:1838,tier:2,
 facts:[["Founded","1838, as the Town of Kansas"],["Role","Trailhead and rail gateway of the Plains"],["Note","Hannibal Bridge, 1869, first rail span of the Missouri"]],
 pop:[[1860,4418],[1900,163752],[1950,456622],[2020,508090]],
 eras:[
  {from:1838,to:1869,text:"Platted in 1838 as the Town of Kansas at the Missouri-Kansas confluence, beside Westport and the Chouteau family's fur landing, it outfitted wagons for the Santa Fe, Oregon, and California trails. Border-war violence over slavery bled through the 1850s, and the Battle of Westport was fought here in 1864. Winning the Hannibal Bridge — the Missouri's first rail crossing, 1869 — beat every rival."},
  {from:1869,to:1930,text:"The bridge made it the gateway of the Plains: stockyards in the West Bottoms second only to Chicago's, packinghouses, grain elevators, and rail yards. George Kessler's parks-and-boulevards system dressed the boomtown after 1893, and 18th and Vine grew into a capital of Black business and music."},
  {from:1930,to:1970,text:"Boss Tom Pendergast's machine ran the wide-open town — jazz flowered after hours with Basie and Charlie Parker while Harry Truman rose through machine politics — until Pendergast's 1939 conviction. The 1951 flood drowned the stockyards district; wartime and postwar plants built aircraft engines and cars."},
  {from:1970,to:2026,text:"The stockyards closed by the 1990s as the economy shifted to freight, finance (a Federal Reserve bank), engineering, and tech across a two-state metro famous for fountains, boulevards, and barbecue. The Chiefs' 2020s championships renewed civic swagger; the city proper passed 508,000 in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Kansas City Public Library, Missouri Valley Special Collections","State Historical Society of Missouri"]},
{id:"omaha",name:"Omaha",lon:-95.93,lat:41.26,founded:1854,appears:1854,joins:1854,tier:3,
 facts:[["Founded","1854, when the Kansas-Nebraska Act opened the land"],["Role","Union Pacific's home; stockyards and insurance city"],["Note","Named for the Umonhon (Omaha) people, whose 1854 cession opened the site"]],
 pop:[[1880,30518],[1900,102555],[1950,251117],[2020,486051]],
 eras:[
  {from:1854,to:1869,text:"Founded by ferry promoters in 1854 the moment the Kansas-Nebraska Act and the Omaha people's forced cession opened the west bank; named for that nation and made territorial capital 1855-67. Lincoln fixed the Union Pacific's eastern base here, ground was broken in December 1863, and the transcontinental line's completion in 1869 set the city's course."},
  {from:1869,to:1900,text:"Union Pacific headquarters and shops, smelters, and from 1883 the South Omaha stockyards and packinghouses drew Czech, Polish, German, Irish, and Black workers. The 1898 Trans-Mississippi Exposition announced the young city's ambitions to a fairgoing nation."},
  {from:1900,to:1960,text:"The 1913 Easter tornado killed over 100. In 1919 a white mob lynched Will Brown at the courthouse and nearly hanged the mayor — one of the Red Summer's atrocities. Father Flanagan founded Boys Town in 1917. Packing peaked as the world's largest livestock market in the mid-1950s while Strategic Air Command settled at Offutt in 1948."},
  {from:1960,to:2026,text:"The stockyards declined and closed by 1999; insurance and finance took over — Mutual of Omaha, First National, and Warren Buffett's Berkshire Hathaway, whose annual meeting fills the arena. The College World Series has been Omaha's June fixture since 1950. The city counted 486,051 people in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","History Nebraska","Durham Museum, Omaha"]},
{id:"minneapolis",name:"Minneapolis–St. Paul",lon:-93.20,lat:44.96,founded:1849,appears:1849,joins:1849,tier:2,
 facts:[["Founded","St. Paul 1849 (territorial capital); Minneapolis chartered 1867"],["Role","Twin Cities: flour-milling capital and rail hub"],["Note","St. Anthony Falls, the Mississippi's only major waterfall, powered the mills"]],
 pop:[[1880,46887],[1900,202718],[1950,521718],[2020,429954]],
 eras:[
  {from:1849,to:1872,text:"Dakota homeland centered on Bdote, the rivers' meeting, with Fort Snelling on the bluff. St. Paul became capital of Minnesota Territory in 1849; the 1851 treaties forced Dakota land cessions, and after the 1862 US-Dakota War the state exiled the Dakota and hanged 38 at Mankato. Milling villages at St. Anthony Falls merged into Minneapolis by 1872."},
  {from:1872,to:1930,text:"St. Anthony Falls powered the world's flour-milling capital from about 1880 to 1930 — Pillsbury and Washburn (General Mills); the 1878 Washburn A Mill explosion killed 18. St. Paul ran the railroads as James J. Hill built the Great Northern. Scandinavian and German immigrants filled both cities' neighborhoods."},
  {from:1930,to:1980,text:"The violent 1934 Teamsters strikes made Minneapolis a union town; Hubert Humphrey's postwar mayoralty confronted its reputation for anti-Semitism. Milling moved out, replaced by headquarters commerce. Skyways knit downtown from 1962, and the American Indian Movement was founded in Minneapolis in 1968."},
  {from:1980,to:2026,text:"A Fortune 500 cluster — Target, 3M, UnitedHealth, Cargill nearby — plus theater second only to New York per capita and Prince's First Avenue scene. Large Hmong and Somali communities remade both cities. The murder of George Floyd by Minneapolis police on May 25, 2020 ignited global protests. Minneapolis counted 429,954 residents in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Minnesota Historical Society","National Park Service — Mississippi National River and Recreation Area"]},
{id:"milwaukee",name:"Milwaukee",lon:-87.91,lat:43.04,founded:1846,appears:1846,joins:1846,tier:3,
 facts:[["Founded","1846, from three rival townsites"],["Role","German Athens; brewing and machinery capital"],["Note","Elected America's first Socialist big-city mayor, 1910"]],
 pop:[[1850,20061],[1900,285315],[1950,637392],[2020,577222]],
 eras:[
  {from:1846,to:1880,text:"Juneautown, Kilbourntown, and Walker's Point — rivals whose feud peaked in the 1845 Bridge War — merged as a city in 1846 on land ceded by Potawatomi and neighboring nations. Refugees of the failed 1848 German revolutions made it the 'German Athens'; wheat shipping gave way to tanning, meatpacking, and the breweries of Pabst, Schlitz, Miller, and Blatz."},
  {from:1880,to:1932,text:"The 'machine shop of the world': Allis-Chalmers, harvester and engine works, and Harley-Davidson from 1903, staffed by German and Polish workers. Voters elected Emil Seidel in 1910, the first Socialist mayor of a major US city, beginning decades of clean 'sewer socialism' government."},
  {from:1932,to:1980,text:"Socialist mayors governed into 1960 (Daniel Hoan, then Frank Zeidler). War industry boomed; the Great Migration arrived late and met rigid housing segregation — Father Groppi's open-housing marches and a deadly riot came in 1967. Beer production peaked as the city's population crested at 741,324 in 1960."},
  {from:1980,to:2026,text:"Schlitz closed in 1981 and Pabst in 1996 as machinery jobs left; Milwaukee became a byword for metropolitan segregation even as Summerfest, Harley-Davidson's museum, and lakefront rebuilding drew visitors. The city hosted the 2024 Republican convention and counted 577,222 residents in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Milwaukee County Historical Society","Encyclopedia of Milwaukee (University of Wisconsin-Milwaukee)"]},
{id:"phoenix",name:"Phoenix",lon:-112.07,lat:33.45,founded:1868,appears:1868,joins:1868,tier:2,
 facts:[["Founded","1868, on the canal lines of the ancient Hohokam"],["Role","Irrigated farm town turned fifth-largest US city"],["Note","Named Phoenix for a city risen on a vanished civilization's works"]],
 pop:[[1900,5544],[1920,29053],[1950,106818],[2020,1608139]],
 eras:[
  {from:1868,to:1912,text:"Jack Swilling's ditch company recut canals the Hohokam had engineered centuries before — the new town, named Phoenix for rising on those ruins, sat in Akimel O'odham and Pee Posh country whose people continued farming the rivers nearby. Alfalfa, grain, and citrus followed; the capital moved here in 1889, Roosevelt Dam (1911) secured water, and statehood came in 1912."},
  {from:1912,to:1945,text:"An irrigated farm capital living on the 'Five C's' — cotton, citrus, cattle, climate, copper commerce — with winter resorts for health-seekers in the dry air. World War II lined the valley with airfields (Luke, Williams) and flight schools, and defense plants planted the seeds of an industrial economy; Japanese Americans were confined at the nearby Gila River camp."},
  {from:1945,to:1990,text:"Air conditioning, cheap land, and boosterism produced one of history's great growth machines: Motorola and electronics from the late 1940s, Sun City retirement suburbs from 1960, population from 106,818 (1950) to 983,403 (1990). The Central Arizona Project began delivering Colorado River water in the 1980s."},
  {from:1990,to:2026,text:"Sprawl swallowed citrus and desert alike; Phoenix passed Philadelphia to become the fifth-largest US city, 1,608,139 by 2020. Semiconductor fabs — TSMC's among the largest US industrial projects — headlined 2020s investment while a record 31 consecutive days at or above 110 degrees in July 2023 and Colorado River shortages defined the stakes of desert urbanism."}
 ],
 sources:["U.S. Census Bureau, decennial census","Arizona Historical Society","Encyclopaedia Britannica"]},
{id:"lasvegas",name:"Las Vegas",lon:-115.14,lat:36.17,founded:1905,appears:1905,joins:1905,tier:2,
 facts:[["Founded","1905, railroad land auction at the springs"],["Role","Casino resort capital of the world"],["Note","'The Meadows' — a Southern Paiute homeland oasis"]],
 pop:[[1920,2304],[1950,24624],[1980,164674],[2020,641903]],
 eras:[
  {from:1905,to:1931,text:"A spring-fed oasis in Southern Paiute homeland — briefly a Mormon fort in 1855 — became a town at the May 1905 auction of lots along the new San Pedro, Los Angeles and Salt Lake Railroad. For a quarter century it stayed a dusty division-point and ranch-supply town of a few thousand."},
  {from:1931,to:1946,text:"In 1931 Nevada legalized casino gambling and eased divorce residency just as thousands of Hoover Dam builders arrived next door; Fremont Street's clubs caught both trades. The war added a gunnery school (later Nellis Air Force Base) and the Basic Magnesium plant at Henderson."},
  {from:1946,to:1989,text:"Bugsy Siegel's Flamingo opened in December 1946, launching the mob-financed Strip: skimmed casinos, Rat Pack showrooms, and mushroom clouds from the Nevada Test Site visible from downtown, 1951-62. Howard Hughes's late-1960s buying spree began the corporate takeover completed by gaming-license reform."},
  {from:1989,to:2026,text:"Steve Wynn's Mirage (1989) began the megaresort era; the metro was America's fastest-growing for two decades, then its foreclosure epicenter in 2008. On October 1, 2017 a gunman killed 60 at a Strip concert, the deadliest mass shooting in modern US history. Major-league sports arrived; Colorado River shortages tightened the city's famous water discipline. 641,903 lived in the city proper in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","UNLV University Libraries, Special Collections","Nevada State Museum, Las Vegas"]},
{id:"anchorage",name:"Anchorage",lon:-149.90,lat:61.22,founded:1915,appears:1915,joins:1915,tier:2,
 facts:[["Founded","1915, Alaska Railroad construction camp"],["Role","Alaska's logistics, military, and corporate center"],["Note","1964 Good Friday earthquake, magnitude 9.2, strongest recorded in North America"]],
 pop:[[1920,1856],[1950,11254],[2020,291247]],
 eras:[
  {from:1915,to:1940,text:"A tent city on Ship Creek in Dena'ina homeland, born in 1915 as construction headquarters for the federal Alaska Railroad; the government auctioned townsite lots that July. After the line's completion in 1923 it settled into life as a small railroad town of a few thousand."},
  {from:1940,to:1964,text:"Fort Richardson and Elmendorf Field, begun 1940, made Anchorage a wartime and Cold War bastion on the great-circle air routes; population leapt from about 4,000 to 44,000 by 1960. On March 27, 1964 the magnitude-9.2 Good Friday earthquake — North America's strongest ever recorded — dropped whole streets and destroyed the Turnagain neighborhood."},
  {from:1964,to:2026,text:"Rebuilt quickly, then transformed by oil: the 1968 Prudhoe Bay strike and 1974-77 Trans-Alaska Pipeline construction made Anchorage the corporate and logistics capital of Alaska, home to Native corporations created by ANCSA in 1971. Its airport ranks among the world's busiest for cargo. About 291,000 people — roughly four in ten Alaskans — lived in the unified municipality in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Anchorage Museum","U.S. Geological Survey"]},
{id:"honolulu",name:"Honolulu",lon:-157.86,lat:21.31,founded:1795,appears:1795,joins:1898,tier:1,
 facts:[["Founded","Kamehameha I based his court here after conquering O'ahu, 1795"],["Role","Capital of the Hawaiian Kingdom, then US territory and state"],["Note","'Iolani Palace had electric lights before the White House"]],
 pop:[[1900,39306],[1950,248034],[2020,350964]],
 eras:[
  {from:1795,to:1845,text:"Kamehameha I took O'ahu at the Battle of Nu'uanu in 1795 and later based his court beside Honolulu's sheltered harbor, the kingdom's window to the world. Sandalwood cargoes to Canton, then whaling fleets, filled the port; American missionaries arrived in 1820, and introduced diseases devastated the Native Hawaiian population. The capital formally moved here from Lahaina in 1845."},
  {from:1845,to:1898,text:"Capital of the Hawaiian Kingdom: Kamehameha III through Kalakaua, who built 'Iolani Palace in 1882 with electric light before the White House had it. Sugar planters' power grew; the 1887 Bayonet Constitution stripped royal authority. On January 17, 1893, with US Marines ashore, planters overthrew Queen Lili'uokalani. Despite mass Native Hawaiian petitions, the US annexed Hawai'i in July 1898."},
  {from:1898,to:1959,text:"Territorial capital and plantation port whose Chinatown burned in 1900 when plague-control fires escaped. Japanese, Chinese, Filipino, Portuguese, and Korean plantation immigration created America's most polyglot city. Japan's December 7, 1941 attack on Pearl Harbor killed over 2,300 and pulled the US into war; the islands lived under martial law until 1944."},
  {from:1959,to:2026,text:"Statehood in August 1959 and jet travel ignited the Waikiki tourism economy and high-rise growth toward Diamond Head. Honolulu became the crossroads of the Pacific — military commands, East-West trade, and a Hawaiian sovereignty movement that grew from the 1970s renaissance of language and voyaging. About 350,000 people lived in the urban core in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Hawai'i State Archives","National Park Service — Pearl Harbor National Memorial"]},
{id:"sitka",name:"Sitka",lon:-135.33,lat:57.05,founded:1804,appears:1804,joins:1867,tier:3,
 facts:[["Founded","1804, as Russian Novo-Arkhangelsk after the Battle of Sitka"],["Role","Capital of Russian America; site of the 1867 transfer"],["Note","Built on Tlingit Sheet'ka after the Kiks.adi defense at Shis'gi Noow"]],
 eras:[
  {from:1804,to:1867,text:"In October 1804 the Russian-American Company under Baranov, backed by a warship, defeated the Kiks.adi Tlingit defending Shis'gi Noow fort and built Novo-Arkhangelsk on Sheet'ka — the Tlingit survival march is still commemorated. Capital of Russian America: sea-otter furs, a shipyard, St. Michael's Cathedral (1848), with Tlingit people resettling beside the palisade from the 1820s."},
  {from:1867,to:1959,text:"On Castle Hill, October 18, 1867, Russia formally transferred Alaska to the United States — purchased for 7.2 million dollars over Tlingit objections that the land was never Russia's to sell. Sitka served as Alaska's first American capital until the government moved to Juneau (formally 1906). The Alaska Native Brotherhood, a pioneering Indigenous civil-rights organization, was founded here in 1912; a naval air station operated in World War II."},
  {from:1959,to:2026,text:"After statehood in 1959 a Japanese-financed pulp mill anchored the economy until it closed in 1993; fishing and fisheries science, cruise tourism, and Coast Guard operations carried on. Sitka National Historical Park preserves the 1804 battleground and totem poles, and the rebuilt St. Michael's Cathedral (burned 1966, restored) still crowns the harbor town of about 8,500."}
 ],
 sources:["National Park Service — Sitka National Historical Park","Alaska State Library and Archives","Encyclopaedia Britannica"]},
{id:"juneau",name:"Juneau",lon:-134.42,lat:58.30,founded:1880,appears:1880,joins:1880,tier:3,
 facts:[["Founded","1880, after Alaska's first major gold strike"],["Role","Alaska's capital since 1906"],["Note","Tlingit leader Kowee guided prospectors to Gold Creek"]],
 pop:[[1900,1864],[1950,5956],[1980,19528],[2020,32255]],
 eras:[
  {from:1880,to:1906,text:"In Aak'w Kwaan Tlingit territory, Chief Kowee guided Joe Juneau and Richard Harris to Gold Creek in October 1880 — the first major gold strike in Alaska. The mining camp became a town almost overnight, and the Treadwell complex across Gastineau Channel on Douglas Island grew into one of the largest gold-mining operations in the world."},
  {from:1906,to:1944,text:"The capital of Alaska moved here from Sitka in 1906, adding government to gold. Treadwell drowned in a 1917 cave-in and flood; the Alaska-Juneau Mine's giant mill on the mountainside carried on until wartime closure in 1944. Fishing fleets and canneries worked the channel."},
  {from:1944,to:2026,text:"In 1945, after Tlingit leader Elizabeth Peratrovich's testimony, the territorial legislature passed the nation's first broad anti-discrimination act. State capital from 1959, road-inaccessible and repeatedly defending its status in capital-move votes, Juneau lives on government, fishing, and a cruise industry topping a million visitors a year; the retreating Mendenhall Glacier and its recent outburst floods track a warming climate. 32,255 people in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","Alaska State Library and Archives","Sealaska Heritage Institute"]},
{id:"sanjuan",name:"San Juan",lon:-66.11,lat:18.47,founded:1521,appears:1750,joins:1898,tier:2,
 facts:[["Founded","1521, by Spanish colonists under Ponce de León"],["Role","Fortified Spanish colonial capital; oldest city under the US flag"],["Note","El Morro's walls repelled the British siege of 1797"]],
 pop:[[1899,32048],[1950,224767],[2020,342259]],
 eras:[
  {from:1750,to:1809,text:"A walled Spanish presidio city on its islet — founded 1521, the oldest European city under the eventual US flag — guarded by El Morro and the vast San Cristobal fortress completed in 1783. Garrison pay from Mexico's situado subsidy sustained it; in 1797 its defenses turned back Abercromby's British invasion fleet."},
  {from:1809,to:1898,text:"Capital of a Spanish colony transformed by the 1815 Cedula de Gracias, which drew immigrants and opened trade; sugar and coffee wealth built the walled city's houses. Slavery was abolished in Puerto Rico in 1873. Spain granted autonomy in 1897 — months before American warships bombarded San Juan in May 1898 and the Treaty of Paris ceded the island."},
  {from:1898,to:1952,text:"Under US military then civilian rule; the 1917 Jones Act imposed citizenship as the university grew at Rio Piedras. Nationalist ferment climaxed in the 1950 revolt, including an attack on La Fortaleza. In 1952 the Commonwealth constitution made San Juan capital of the Estado Libre Asociado, amid Operation Bootstrap's rush of industrialization."},
  {from:1952,to:2026,text:"Bootstrap factories, then pharmaceuticals and tourism, urbanized the metro while Old San Juan's blue-cobbled core was restored. Debt crisis brought the federal PROMESA board in 2016; Hurricane Maria, September 20, 2017, caused months-long blackouts and thousands of excess deaths island-wide. Mass protests in San Juan's streets forced the governor's resignation in 2019. The municipio counted 342,259 people in 2020."}
 ],
 sources:["U.S. Census Bureau, decennial census","National Park Service — San Juan National Historic Site","Library of Congress"]},
{id:"manila",name:"Manila",lon:120.98,lat:14.60,founded:1571,appears:1898,joins:1898,leaves:1946,tier:1,
 facts:[["Founded","1571, Spanish capital of the Philippines (Maynilà)"],["Role","Colonial capital under Spain, then the United States, 1898–1946"],["Note","Intramuros, the walled city, was the seat of 350 years of colonial rule"]],
 pop:[[1903,219928],[1939,623492],[1960,1138611],[1990,1601234],[2020,1846513]],
 eras:[
  {from:1898,to:1946,text:"Dewey destroys the Spanish squadron in Manila Bay in May 1898; within a year American troops and the Philippine Republic are at war outside the walls. As capital of the U.S. insular government, Manila gains English-language schools, Burnham-planned boulevards and port works — the 'Pearl of the Orient' — until Japanese occupation (1942) and the 1945 battle that kills roughly 100,000 civilians and destroys the old city."},
  {from:1946,to:2026,text:"Capital of the independent republic (with an interlude when Quezon City held the title, 1948–1976), Manila rebuilds and swells into one of the world's densest megacities — over 13 million people in the metropolitan region. Jeepneys descended from U.S. Army surplus, a large English-speaking workforce, and deep family ties to America carry the colonial half-century forward."}
 ],
 sources:["Philippine Statistics Authority, census of population","Library of Congress — The World of 1898","National Historical Commission of the Philippines"]},
];
